// src/pages/PostInternship.jsx
import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

export default function PostInternship() {
  const { currentUser } = useAuth();
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    title: "",
    company: "",
    location: "",
    description: "",
    stipend: "",
    duration: "",
    applyLink: "",
  });

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const config = {
        headers: {
          Authorization: `Bearer ${currentUser?.token}`,
        },
      };
      await axios.post("http://localhost:5000/api/internships", formData, config);
      alert("Internship posted successfully!");
      navigate("/internship");
    } catch (err) {
      console.error("Error posting internship:", err);
      alert("Failed to post internship.");
    }
  };

  return (
    <div className="post-internship-page" style={{ padding: "2rem" }}>
      <h2>Post a New Internship</h2>
      <form onSubmit={handleSubmit} style={{ display: "grid", gap: "1rem", maxWidth: "500px" }}>
        <input type="text" name="title" placeholder="Internship Title" onChange={handleChange} required />
        <input type="text" name="company" placeholder="Company Name" onChange={handleChange} required />
        <input type="text" name="location" placeholder="Location" onChange={handleChange} required />
        <input type="text" name="stipend" placeholder="Stipend" onChange={handleChange} />
        <input type="text" name="duration" placeholder="Duration (e.g., 3 months)" onChange={handleChange} />
        <input type="url" name="applyLink" placeholder="Application Link (if any)" onChange={handleChange} />
        <textarea name="description" placeholder="Description" onChange={handleChange} required />
        <button type="submit" className="btn">Post Internship</button>
      </form>
    </div>
  );
}
